export const postApiDaemonVersions = (
  postApiDaemonVersionsBody: PostApiDaemonVersionsBody,
  signal?: AbortSignal,
) => {
  const formData = new FormData();
  if (postApiDaemonVersionsBody.file !== undefined) {
    formData.append(`file`, postApiDaemonVersionsBody.file);
  }
  if (postApiDaemonVersionsBody.channel !== undefined) {
    formData.append(`channel`, postApiDaemonVersionsBody.channel);
  }
  if (postApiDaemonVersionsBody.notes !== undefined) {
    formData.append(`notes`, postApiDaemonVersionsBody.notes);
  }
  if (postApiDaemonVersionsBody.sha256 !== undefined) {
    formData.append(`sha256`, postApiDaemonVersionsBody.sha256);
  }
  if (postApiDaemonVersionsBody.gitSha !== undefined) {
    formData.append(`gitSha`, postApiDaemonVersionsBody.gitSha);
  }

  return customClient<PublishDaemonVersionResponse>({
    url: `/api/daemon-versions`,
    method: "POST",
    headers: { "Content-Type": "multipart/form-data" },
    data: formData,
    signal,
  });
};

